const reviews = $input.all().map(item => item.json);

// Get DataTable schema
const table = $("Create Reviews DataTable").first().json;

// Extract column names
const columns = table.columns.map(col => col.name);

// Map reviews to table schema
const formattedReviews = reviews.map(review => {

  const mapped = {};

  columns.forEach(col => {

    if (col === "review_id") mapped[col] = review.review_id || null;

    if (col === "review_text") mapped[col] = review.snippet || null;

    if (col === "rating") mapped[col] = review.rating || null;

    if (col === "sentiment") mapped[col] = review.output?.sentiment || null;

    if (col === "score") mapped[col] = review.output?.score || null;

    if (col === "reason") mapped[col] = review.output?.reason || null;

    if (col === "analyzed_at") mapped[col] = new Date().toISOString();

  });

  return { json: mapped };

});

return formattedReviews;
